export function findLexiconSlug(slug) {
  const key = String(slug || "").toLowerCase();
  return LEXICON_ENTRIES.find((e) => String(e.slug).toLowerCase() === key) ?? null;
}

export function lexiconCountByZone(zone) {
  const z = String(zone || "").toLowerCase();
  return LEXICON_ENTRIES.filter((e) => e.zone === z).length;
}
